import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Secure code with proper input validation and handling
        byte[] buffer = new byte[Math.min(name.length(), 10)];
        System.arraycopy(name.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, buffer.length);

        System.out.println("Hello, " + new String(buffer, StandardCharsets.UTF_8));
    }
}

